import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

const stream = client.messages.stream({
  model: "claude-opus-4-8",
  max_tokens: 2048,
  messages: [{ role: "user", content: "Напиши сказку про робота-садовника" }],
});

stream.on("text", (delta) => process.stdout.write(delta)); // печатаем по кусочкам

const full = await stream.finalMessage(); // а в конце — полное сообщение
console.log("\nТокенов на выходе:", full.usage.output_tokens);
